INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('N1_s_1', 'N1', 1, 'Calcule : 25 - 4 . 3', 'Calculate: 25 - 4 . 3', 'Bereken: 25 - 4 . 3', '13', 0, 'Effectue d''abord la multiplication, puis la soustraction.', 'Do the multiplication first, then the subtraction.', 'Doe eerst de vermenigvuldiging, dan de aftrekking.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('N1_s_2', 'N1', 1, 'Calcule : 6 + 18 : 3', 'Calculate: 6 + 18 : 3', 'Bereken: 6 + 18 : 3', '12', 0, 'Effectue d''abord la division, puis l''addition.', 'Do the division first, then the addition.', 'Doe eerst de deling, dan de optelling.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('N1_s_3', 'N1', 1, 'Calcule : 7 . 8 - 15', 'Calculate: 7 . 8 - 15', 'Bereken: 7 . 8 - 15', '41', 0, 'Effectue d''abord la multiplication, puis la soustraction.', 'Do the multiplication first, then the subtraction.', 'Doe eerst de vermenigvuldiging, dan de aftrekking.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('N1_s_4', 'N1', 1, 'Calcule : 50 - 3 . 9', 'Calculate: 50 - 3 . 9', 'Bereken: 50 - 3 . 9', '23', 0, 'Effectue d''abord la multiplication, puis la soustraction.', 'Do the multiplication first, then the subtraction.', 'Doe eerst de vermenigvuldiging, dan de aftrekking.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('N1_s_5', 'N1', 1, 'Calcule : 12 + 5 . 6', 'Calculate: 12 + 5 . 6', 'Bereken: 12 + 5 . 6', '42', 0, 'La multiplication est prioritaire sur l''addition.', 'Multiplication takes priority over addition.', 'Vermenigvuldiging heeft voorrang op optelling.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('N1_s_6', 'N1', 1, 'Calcule : 48 : 6 + 3 . 7', 'Calculate: 48 : 6 + 3 . 7', 'Bereken: 48 : 6 + 3 . 7', '29', 0, 'Effectue d''abord la division et la multiplication, puis l''addition.', 'Do the division and multiplication first, then the addition.', 'Doe eerst de deling en vermenigvuldiging, dan de optelling.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('N1_s_7', 'N1', 1, 'Calcule : 100 - 8 . 7 + 3', 'Calculate: 100 - 8 . 7 + 3', 'Bereken: 100 - 8 . 7 + 3', '47', 0, 'Effectue d''abord la multiplication, puis les additions et soustractions de gauche à droite.', 'Do the multiplication first, then additions and subtractions from left to right.', 'Doe eerst de vermenigvuldiging, dan optellingen en aftrekkingen van links naar rechts.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('N1_s_18', 'N1', 2, 'Calcule : 40 - 5 . 2²', 'Calculate: 40 - 5 . 2²', 'Bereken: 40 - 5 . 2²', '20', 0, 'Calcule d''abord la puissance, puis la multiplication, puis la soustraction.', 'Calculate the power first, then the multiplication, then the subtraction.', 'Bereken eerst de macht, dan de vermenigvuldiging, dan de aftrekking.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('N1_s_19', 'N1', 2, 'Calcule : 56 - 5 . 2³', 'Calculate: 56 - 5 . 2³', 'Bereken: 56 - 5 . 2³', '16', 0, 'Calcule d''abord 2³, puis la multiplication, puis la soustraction.', 'Calculate 2³ first, then the multiplication, then the subtraction.', 'Bereken eerst 2³, dan de vermenigvuldiging, dan de aftrekking.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('N1_s_20', 'N1', 2, 'Calcule : 3² + 4 . 5', 'Calculate: 3² + 4 . 5', 'Bereken: 3² + 4 . 5', '29', 0, 'Calcule d''abord la puissance et la multiplication, puis additionne.', 'Calculate the power and the multiplication first, then add.', 'Bereken eerst de macht en de vermenigvuldiging, tel dan op.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('N1_s_21', 'N1', 2, 'Calcule : 5² - 3 . 4', 'Calculate: 5² - 3 . 4', 'Bereken: 5² - 3 . 4', '13', 0, 'Calcule d''abord 5², puis la multiplication, puis la soustraction.', 'Calculate 5² first, then the multiplication, then the subtraction.', 'Bereken eerst 5², dan de vermenigvuldiging, dan de aftrekking.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('N1_s_22', 'N1', 2, 'Calcule : 2⁴ + 3² . 2', 'Calculate: 2⁴ + 3² . 2', 'Bereken: 2⁴ + 3² . 2', '34', 0, 'Calcule d''abord les puissances, puis la multiplication, puis l''addition.', 'Calculate powers first, then the multiplication, then the addition.', 'Bereken eerst de machten, dan de vermenigvuldiging, dan de optelling.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('N1_s_23', 'N1', 2, 'Calcule : 75 - 3 . 3²', 'Calculate: 75 - 3 . 3²', 'Bereken: 75 - 3 . 3²', '48', 0, 'Calcule d''abord 3², puis la multiplication, puis la soustraction.', 'Calculate 3² first, then the multiplication, then the subtraction.', 'Bereken eerst 3², dan de vermenigvuldiging, dan de aftrekking.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('N1_s_24', 'N1', 2, 'Calcule : 4³ - 2 . 5²', 'Calculate: 4³ - 2 . 5²', 'Bereken: 4³ - 2 . 5²', '14', 0, 'Calcule les puissances d''abord : 4³ et 5², puis la multiplication, puis la soustraction.', 'Calculate powers first: 4³ and 5², then the multiplication, then the subtraction.', 'Bereken eerst de machten: 4³ en 5², dan de vermenigvuldiging, dan de aftrekking.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('N1_s_35', 'N1', 3, 'Calcule : 8 . (3 - 5)³ + 4', 'Calculate: 8 . (3 - 5)³ + 4', 'Bereken: 8 . (3 - 5)³ + 4', '-60', 0, 'Calcule d''abord la parenthèse, puis la puissance, puis la multiplication, puis l''addition.', 'Calculate the parentheses first, then the power, then the multiplication, then the addition.', 'Bereken eerst de haakjes, dan de macht, dan de vermenigvuldiging, dan de optelling.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('N1_s_36', 'N1', 3, 'Calcule : (-2)² . 3 + (-5)', 'Calculate: (-2)² . 3 + (-5)', 'Bereken: (-2)² . 3 + (-5)', '7', 0, '(-2)² = 4. Ensuite, multiplie par 3, puis ajoute (-5).', '(-2)² = 4. Then multiply by 3, then add (-5).', '(-2)² = 4. Vermenigvuldig dan met 3, tel dan (-5) op.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('N1_s_37', 'N1', 3, 'Calcule : 5 . (-3)² - 2 . 4', 'Calculate: 5 . (-3)² - 2 . 4', 'Bereken: 5 . (-3)² - 2 . 4', '37', 0, '(-3)² = 9 (le carré d''un négatif est positif). Puis effectue les multiplications avant la soustraction.', '(-3)² = 9 (squaring a negative gives a positive). Then do multiplications before subtraction.', '(-3)² = 9 (het kwadraat van een negatief is positief). Doe dan vermenigvuldigingen voor de aftrekking.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('N1_s_38', 'N1', 3, 'Calcule : (-4)³ + 100', 'Calculate: (-4)³ + 100', 'Bereken: (-4)³ + 100', '36', 0, '(-4)³ = -64 (le cube d''un négatif reste négatif). Puis ajoute 100.', '(-4)³ = -64 (cubing a negative stays negative). Then add 100.', '(-4)³ = -64 (de derde macht van een negatief blijft negatief). Tel dan 100 op.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('N1_s_39', 'N1', 3, 'Calcule : 3 . (-2)³ + 5²', 'Calculate: 3 . (-2)³ + 5²', 'Bereken: 3 . (-2)³ + 5²', '1', 0, 'Calcule (-2)³ = -8 et 5² = 25, puis effectue les opérations.', 'Calculate (-2)³ = -8 and 5² = 25, then do the operations.', 'Bereken (-2)³ = -8 en 5² = 25, voer dan de bewerkingen uit.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('N1_s_40', 'N1', 3, 'Calcule : (7 - 10)² . 4 - 6', 'Calculate: (7 - 10)² . 4 - 6', 'Bereken: (7 - 10)² . 4 - 6', '30', 0, 'Calcule d''abord la parenthèse (7 - 10 = -3), puis le carré, puis la multiplication.', 'Calculate the parentheses first (7 - 10 = -3), then the square, then the multiplication.', 'Bereken eerst de haakjes (7 - 10 = -3), dan het kwadraat, dan de vermenigvuldiging.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('N2_s_1', 'N2', 1, 'Quel est le reste de 17 divise par 5 ?', 'What is the remainder of 17 divided by 5?', 'Wat is de rest van 17 gedeeld door 5?', '2', 0, '17 = 3 x 5 + reste. Quel est le reste ?', '17 = 3 x 5 + remainder. What is the remainder?', '17 = 3 x 5 + rest. Wat is de rest?');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('N2_s_2', 'N2', 1, 'Quel est le reste de 23 divise par 4 ?', 'What is the remainder of 23 divided by 4?', 'Wat is de rest van 23 gedeeld door 4?', '3', 0, '23 = 5 x 4 + reste. Quel est le reste ?', '23 = 5 x 4 + remainder. What is the remainder?', '23 = 5 x 4 + rest. Wat is de rest?');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('N2_s_3', 'N2', 1, 'Quel est le reste de 29 divise par 6 ?', 'What is the remainder of 29 divided by 6?', 'Wat is de rest van 29 gedeeld door 6?', '5', 0, '29 = 4 x 6 + reste. Quel est le reste ?', '29 = 4 x 6 + remainder. What is the remainder?', '29 = 4 x 6 + rest. Wat is de rest?');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('N2_s_4', 'N2', 1, 'Quel est le plus grand diviseur commun (PGCD) de 12 et 8 ?', 'What is the greatest common divisor (GCD) of 12 and 8?', 'Wat is de grootste gemene deler (GGD) van 12 en 8?', '4', 0, 'Liste les diviseurs de 12 et de 8, puis trouve le plus grand commun.', 'List the divisors of 12 and 8, then find the largest common one.', 'Lijst de delers van 12 en 8, en vind de grootste gemeenschappelijke.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('N2_s_5', 'N2', 1, 'Quel est le PGCD de 15 et 25 ?', 'What is the GCD of 15 and 25?', 'Wat is de GGD van 15 en 25?', '5', 0, 'Les diviseurs de 15 sont 1, 3, 5, 15. Les diviseurs de 25 sont 1, 5, 25.', 'The divisors of 15 are 1, 3, 5, 15. The divisors of 25 are 1, 5, 25.', 'De delers van 15 zijn 1, 3, 5, 15. De delers van 25 zijn 1, 5, 25.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('N2_s_6', 'N2', 1, 'Quel est le PGCD de 18 et 24 ?', 'What is the GCD of 18 and 24?', 'Wat is de GGD van 18 en 24?', '6', 0, 'Decompose 18 = 2 x 3 x 3 et 24 = 2 x 2 x 2 x 3, puis prends les facteurs communs.', 'Decompose 18 = 2 x 3 x 3 and 24 = 2 x 2 x 2 x 3, then take common factors.', 'Ontbind 18 = 2 x 3 x 3 en 24 = 2 x 2 x 2 x 3, en neem de gemeenschappelijke factoren.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('N2_s_7', 'N2', 1, 'Si a = 3, calcule : 2a + 5', 'If a = 3, calculate: 2a + 5', 'Als a = 3, bereken: 2a + 5', '11', 0, 'Remplace a par 3 : 2 x 3 + 5.', 'Replace a with 3: 2 x 3 + 5.', 'Vervang a door 3: 2 x 3 + 5.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('N2_s_18', 'N2', 2, 'Quel est le PPCM de 6 et 8 ?', 'What is the LCM of 6 and 8?', 'Wat is het KGV van 6 en 8?', '24', 0, 'Decompose : 6 = 2 x 3, 8 = 2 x 2 x 2. Le PPCM = 2^3 x 3 = 24.', 'Decompose: 6 = 2 x 3, 8 = 2 x 2 x 2. The LCM = 2^3 x 3 = 24.', 'Ontbind: 6 = 2 x 3, 8 = 2 x 2 x 2. Het KGV = 2^3 x 3 = 24.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('N2_s_19', 'N2', 2, 'Quel est le PPCM de 9 et 12 ?', 'What is the LCM of 9 and 12?', 'Wat is het KGV van 9 en 12?', '36', 0, '9 = 3 x 3 et 12 = 2 x 2 x 3. Le PPCM = 2^2 x 3^2 = 36.', '9 = 3 x 3 and 12 = 2 x 2 x 3. The LCM = 2^2 x 3^2 = 36.', '9 = 3 x 3 en 12 = 2 x 2 x 3. Het KGV = 2^2 x 3^2 = 36.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('N2_s_20', 'N2', 2, 'Si a = 4 et b = -2, calcule : a + 3b', 'If a = 4 and b = -2, calculate: a + 3b', 'Als a = 4 en b = -2, bereken: a + 3b', '-2', 0, 'Remplace : 4 + 3 x (-2) = 4 - 6.', 'Replace: 4 + 3 x (-2) = 4 - 6.', 'Vervang: 4 + 3 x (-2) = 4 - 6.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('N2_s_21', 'N2', 2, 'Si a = 4 et b = -2, calcule : a^2 - 3b', 'If a = 4 and b = -2, calculate: a^2 - 3b', 'Als a = 4 en b = -2, bereken: a^2 - 3b', '22', 0, 'a^2 = 16. Puis 16 - 3 x (-2) = 16 + 6 = 22.', 'a^2 = 16. Then 16 - 3 x (-2) = 16 + 6 = 22.', 'a^2 = 16. Dan 16 - 3 x (-2) = 16 + 6 = 22.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('N2_s_22', 'N2', 2, 'Quel est le PGCD de 28 et 42 ?', 'What is the GCD of 28 and 42?', 'Wat is de GGD van 28 en 42?', '14', 0, '28 = 2 x 2 x 7 et 42 = 2 x 3 x 7. PGCD = 2 x 7 = 14.', '28 = 2 x 2 x 7 and 42 = 2 x 3 x 7. GCD = 2 x 7 = 14.', '28 = 2 x 2 x 7 en 42 = 2 x 3 x 7. GGD = 2 x 7 = 14.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('N2_s_23', 'N2', 2, 'Combien y a-t-il de diviseurs de 20 ?', 'How many divisors does 20 have?', 'Hoeveel delers heeft 20?', '6', 0, 'Les diviseurs de 20 : 1, 2, 4, 5, 10, 20.', 'The divisors of 20: 1, 2, 4, 5, 10, 20.', 'De delers van 20: 1, 2, 4, 5, 10, 20.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('N2_s_24', 'N2', 2, 'Quel est le PPCM de 10 et 15 ?', 'What is the LCM of 10 and 15?', 'Wat is het KGV van 10 en 15?', '30', 0, '10 = 2 x 5 et 15 = 3 x 5. PPCM = 2 x 3 x 5 = 30.', '10 = 2 x 5 and 15 = 3 x 5. LCM = 2 x 3 x 5 = 30.', '10 = 2 x 5 en 15 = 3 x 5. KGV = 2 x 3 x 5 = 30.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('N2_s_35', 'N2', 3, 'Si x = -3, calcule : x^2 + 2x - 1', 'If x = -3, calculate: x^2 + 2x - 1', 'Als x = -3, bereken: x^2 + 2x - 1', '2', 0, '(-3)^2 + 2 x (-3) - 1 = 9 - 6 - 1 = 2.', '(-3)^2 + 2 x (-3) - 1 = 9 - 6 - 1 = 2.', '(-3)^2 + 2 x (-3) - 1 = 9 - 6 - 1 = 2.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('N2_s_36', 'N2', 3, 'Quel est le PGCD de 36 et 48 ?', 'What is the GCD of 36 and 48?', 'Wat is de GGD van 36 en 48?', '12', 0, '36 = 2^2 x 3^2 et 48 = 2^4 x 3. PGCD = 2^2 x 3 = 12.', '36 = 2^2 x 3^2 and 48 = 2^4 x 3. GCD = 2^2 x 3 = 12.', '36 = 2^2 x 3^2 en 48 = 2^4 x 3. GGD = 2^2 x 3 = 12.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('N2_s_37', 'N2', 3, 'Combien y a-t-il de nombres premiers entre 1 et 20 ?', 'How many prime numbers are there between 1 and 20?', 'Hoeveel priemgetallen zijn er tussen 1 en 20?', '8', 0, 'Les nombres premiers entre 1 et 20 : 2, 3, 5, 7, 11, 13, 17, 19.', 'The prime numbers between 1 and 20: 2, 3, 5, 7, 11, 13, 17, 19.', 'De priemgetallen tussen 1 en 20: 2, 3, 5, 7, 11, 13, 17, 19.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('N2_s_38', 'N2', 3, 'Si a = 2 et b = -3, calcule : a^2 - b^2', 'If a = 2 and b = -3, calculate: a^2 - b^2', 'Als a = 2 en b = -3, bereken: a^2 - b^2', '-5', 0, 'a^2 = 4 et b^2 = 9. Donc 4 - 9 = -5.', 'a^2 = 4 and b^2 = 9. So 4 - 9 = -5.', 'a^2 = 4 en b^2 = 9. Dus 4 - 9 = -5.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('N2_s_39', 'N2', 3, 'Quel est le PPCM de 12 et 18 ?', 'What is the LCM of 12 and 18?', 'Wat is het KGV van 12 en 18?', '36', 0, '12 = 2^2 x 3 et 18 = 2 x 3^2. PPCM = 2^2 x 3^2 = 36.', '12 = 2^2 x 3 and 18 = 2 x 3^2. LCM = 2^2 x 3^2 = 36.', '12 = 2^2 x 3 en 18 = 2 x 3^2. KGV = 2^2 x 3^2 = 36.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('N2_s_40', 'N2', 3, 'Si x = -2, calcule : 2x^2 - 3x + 4', 'If x = -2, calculate: 2x^2 - 3x + 4', 'Als x = -2, bereken: 2x^2 - 3x + 4', '18', 0, '2 x (-2)^2 - 3 x (-2) + 4 = 2 x 4 + 6 + 4 = 8 + 6 + 4 = 18.', '2 x (-2)^2 - 3 x (-2) + 4 = 2 x 4 + 6 + 4 = 8 + 6 + 4 = 18.', '2 x (-2)^2 - 3 x (-2) + 4 = 2 x 4 + 6 + 4 = 8 + 6 + 4 = 18.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('N3_s_1', 'N3', 1, 'Calcule : 3 + 4 . 2', 'Calculate: 3 + 4 . 2', 'Bereken: 3 + 4 . 2', '11', 0, 'Effectue d''abord la multiplication.', 'Do the multiplication first.', 'Doe eerst de vermenigvuldiging.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('N3_s_2', 'N3', 1, 'Calcule : 20 - 3 . 5', 'Calculate: 20 - 3 . 5', 'Bereken: 20 - 3 . 5', '5', 0, 'La multiplication est prioritaire.', 'Multiplication comes first.', 'Vermenigvuldiging gaat voor.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('N3_s_3', 'N3', 1, 'Calcule : 6 . 3 + 7', 'Calculate: 6 . 3 + 7', 'Bereken: 6 . 3 + 7', '25', 0, 'Multiplie d''abord, puis additionne.', 'Multiply first, then add.', 'Vermenigvuldig eerst, tel dan op.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('N3_s_4', 'N3', 1, 'Calcule : 15 - 2 . 4', 'Calculate: 15 - 2 . 4', 'Bereken: 15 - 2 . 4', '7', 0, 'Effectue d''abord 2 . 4.', 'Do 2 . 4 first.', 'Bereken eerst 2 . 4.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('N3_s_5', 'N3', 1, 'Calcule : 8 + 5 . 3', 'Calculate: 8 + 5 . 3', 'Bereken: 8 + 5 . 3', '23', 0, 'La multiplication est prioritaire sur l''addition.', 'Multiplication before addition.', 'Vermenigvuldiging voor optelling.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('N3_s_16', 'N3', 1, 'Calcule : 10 + 18 : 3', 'Calculate: 10 + 18 : 3', 'Bereken: 10 + 18 : 3', '16', 0, 'Effectue d''abord la division.', 'Do the division first.', 'Doe eerst de deling.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('N3_s_17', 'N3', 1, 'Calcule : 8 . 2 - 3', 'Calculate: 8 . 2 - 3', 'Bereken: 8 . 2 - 3', '13', 0, 'Multiplie d''abord, puis soustrais.', 'Multiply first, then subtract.', 'Vermenigvuldig eerst, trek dan af.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('N3_s_6', 'N3', 2, 'Calcule : (4 + 3) . 5', 'Calculate: (4 + 3) . 5', 'Bereken: (4 + 3) . 5', '35', 0, 'Calcule d''abord ce qui est entre parenthèses.', 'Calculate parentheses first.', 'Bereken eerst wat tussen haakjes staat.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('N3_s_7', 'N3', 2, 'Calcule : 2 . (10 - 3) + 4', 'Calculate: 2 . (10 - 3) + 4', 'Bereken: 2 . (10 - 3) + 4', '18', 0, 'Parenthèses d''abord, puis ., puis +.', 'Parentheses, then ., then +.', 'Haakjes eerst, dan ., dan +.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('N3_s_8', 'N3', 2, 'Calcule : 36 : (2 + 4) . 3', 'Calculate: 36 : (2 + 4) . 3', 'Bereken: 36 : (2 + 4) . 3', '18', 0, 'Parenthèses d''abord, puis de gauche à droite.', 'Parentheses first, then left to right.', 'Haakjes eerst, dan van links naar rechts.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('N3_s_9', 'N3', 2, 'Calcule : (8 - 3) . (2 + 4)', 'Calculate: (8 - 3) . (2 + 4)', 'Bereken: (8 - 3) . (2 + 4)', '30', 0, 'Calcule chaque parenthèse, puis multiplie.', 'Evaluate each parenthesis, then multiply.', 'Bereken elke haakje, vermenigvuldig dan.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('N3_s_10', 'N3', 2, 'Calcule : 50 - 2 . (3 + 7)', 'Calculate: 50 - 2 . (3 + 7)', 'Bereken: 50 - 2 . (3 + 7)', '30', 0, 'Parenthèses, puis multiplication, puis soustraction.', 'Parentheses, then multiplication, then subtraction.', 'Haakjes, dan vermenigvuldiging, dan aftrekking.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('N3_s_28', 'N3', 2, 'Calcule : (9 - 4) . 6', 'Calculate: (9 - 4) . 6', 'Bereken: (9 - 4) . 6', '30', 0, 'Calcule d''abord la parenthèse, puis multiplie.', 'Evaluate the parentheses first, then multiply.', 'Bereken eerst de haakjes, vermenigvuldig dan.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('N3_s_29', 'N3', 2, 'Calcule : 3 . (7 + 5) - 10', 'Calculate: 3 . (7 + 5) - 10', 'Bereken: 3 . (7 + 5) - 10', '26', 0, 'Parenthèses d''abord, puis ., puis -.', 'Parentheses first, then ., then -.', 'Haakjes eerst, dan ., dan -.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('N3_s_11', 'N3', 3, 'Calcule : 3 . (4 + 2) - (10 - 3)', 'Calculate: 3 . (4 + 2) - (10 - 3)', 'Bereken: 3 . (4 + 2) - (10 - 3)', '11', 0, 'Calcule chaque parenthèse séparément.', 'Evaluate each set of parentheses.', 'Bereken elke haakje apart.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('N3_s_12', 'N3', 3, 'Calcule : (2 + 3)² - 4 . 3', 'Calculate: (2 + 3)² - 4 . 3', 'Bereken: (2 + 3)² - 4 . 3', '13', 0, 'Parenthèses, puis puissance, puis multiplication.', 'Parentheses, then power, then multiplication.', 'Haakjes, dan macht, dan vermenigvuldiging.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('N3_s_13', 'N3', 3, 'Calcule : 48 : (2 . (1 + 3))', 'Calculate: 48 : (2 . (1 + 3))', 'Bereken: 48 : (2 . (1 + 3))', '6', 0, 'Commence par les parenthèses intérieures.', 'Start with the inner parentheses.', 'Begin met de binnenste haakjes.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('N3_s_14', 'N3', 3, 'Calcule : (15 - 3 . 2) . (1 + 2)', 'Calculate: (15 - 3 . 2) . (1 + 2)', 'Bereken: (15 - 3 . 2) . (1 + 2)', '27', 0, 'Dans la 1re parenthèse, la . est prioritaire.', 'In the 1st bracket, . comes first.', 'In het 1e haakje gaat . voor.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('N3_s_15', 'N3', 3, 'Calcule : 100 - 3 . (2 . 5 + 4)', 'Calculate: 100 - 3 . (2 . 5 + 4)', 'Bereken: 100 - 3 . (2 . 5 + 4)', '58', 0, 'Dans la parenthèse : . d''abord, puis +.', 'Inside the bracket: . first, then +.', 'Binnen haakjes: . eerst, dan +.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('N3_s_40', 'N3', 3, 'Calcule : (3 + 4)² - 2 . 10', 'Calculate: (3 + 4)² - 2 . 10', 'Bereken: (3 + 4)² - 2 . 10', '29', 0, 'Parenthèses, puis puissance, puis multiplication, puis soustraction.', 'Parentheses, then power, then multiplication, then subtraction.', 'Haakjes, dan macht, dan vermenigvuldiging, dan aftrekking.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('N4_s_1', 'N4', 1, 'Résous : x + 7 = 15', 'Solve: x + 7 = 15', 'Los op: x + 7 = 15', '8', 0, 'Isole x : x = 15 - 7.', 'Isolate x: x = 15 - 7.', 'Isoleer x: x = 15 - 7.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('N4_s_2', 'N4', 1, 'Résous : x - 9 = 14', 'Solve: x - 9 = 14', 'Los op: x - 9 = 14', '23', 0, 'Ajoute 9 des deux côtés.', 'Add 9 to both sides.', 'Tel 9 op aan beide kanten.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('N4_s_3', 'N4', 1, 'Résous : 3x = 21', 'Solve: 3x = 21', 'Los op: 3x = 21', '7', 0, 'Divise les deux côtés par 3.', 'Divide both sides by 3.', 'Deel beide kanten door 3.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('N4_s_4', 'N4', 1, 'Résous : 5x = 45', 'Solve: 5x = 45', 'Los op: 5x = 45', '9', 0, 'Divise les deux côtés par 5.', 'Divide both sides by 5.', 'Deel beide kanten door 5.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('N4_s_5', 'N4', 1, 'Résous : x + 12 = 30', 'Solve: x + 12 = 30', 'Los op: x + 12 = 30', '18', 0, 'x = 30 - 12.', 'x = 30 - 12.', 'x = 30 - 12.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('N4_s_6', 'N4', 1, 'Résous : 2x + 3 = 11', 'Solve: 2x + 3 = 11', 'Los op: 2x + 3 = 11', '4', 0, '2x = 11 - 3 = 8, donc x = 4.', '2x = 11 - 3 = 8, so x = 4.', '2x = 11 - 3 = 8, dus x = 4.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('N4_s_7', 'N4', 1, 'Résous : 4x - 5 = 15', 'Solve: 4x - 5 = 15', 'Los op: 4x - 5 = 15', '5', 0, '4x = 15 + 5 = 20, donc x = 5.', '4x = 15 + 5 = 20, so x = 5.', '4x = 15 + 5 = 20, dus x = 5.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('N4_s_41', 'N4', 2, 'Résous : 2(x + 3) = 16', 'Solve: 2(x + 3) = 16', 'Los op: 2(x + 3) = 16', '5', 0, '2x + 6 = 16, donc 2x = 10, x = 5.', '2x + 6 = 16, so 2x = 10, x = 5.', '2x + 6 = 16, dus 2x = 10, x = 5.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('N4_s_42', 'N4', 2, 'Résous : 3(x - 4) = 15', 'Solve: 3(x - 4) = 15', 'Los op: 3(x - 4) = 15', '9', 0, '3x - 12 = 15, donc 3x = 27, x = 9.', '3x - 12 = 15, so 3x = 27, x = 9.', '3x - 12 = 15, dus 3x = 27, x = 9.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('N4_s_43', 'N4', 2, 'Résous : 5x + 3 = 2x + 18', 'Solve: 5x + 3 = 2x + 18', 'Los op: 5x + 3 = 2x + 18', '5', 0, '5x - 2x = 18 - 3, donc 3x = 15, x = 5.', '5x - 2x = 18 - 3, so 3x = 15, x = 5.', '5x - 2x = 18 - 3, dus 3x = 15, x = 5.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('N4_s_44', 'N4', 2, 'Résous : 4(x + 2) = 3x + 14', 'Solve: 4(x + 2) = 3x + 14', 'Los op: 4(x + 2) = 3x + 14', '6', 0, '4x + 8 = 3x + 14, donc x = 6.', '4x + 8 = 3x + 14, so x = 6.', '4x + 8 = 3x + 14, dus x = 6.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('N4_s_45', 'N4', 2, 'Résous : 2(x + 3) = -8', 'Solve: 2(x + 3) = -8', 'Los op: 2(x + 3) = -8', '-7', 0, '2x + 6 = -8, donc 2x = -14, x = -7.', '2x + 6 = -8, so 2x = -14, x = -7.', '2x + 6 = -8, dus 2x = -14, x = -7.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('N4_s_46', 'N4', 2, 'Résous : 7x - 3 = 4x + 12', 'Solve: 7x - 3 = 4x + 12', 'Los op: 7x - 3 = 4x + 12', '5', 0, '7x - 4x = 12 + 3, donc 3x = 15, x = 5.', '7x - 4x = 12 + 3, so 3x = 15, x = 5.', '7x - 4x = 12 + 3, dus 3x = 15, x = 5.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('N4_s_47', 'N4', 2, 'Résous : 3(x - 2) + 5 = 20', 'Solve: 3(x - 2) + 5 = 20', 'Los op: 3(x - 2) + 5 = 20', '7', 0, '3x - 6 + 5 = 20, donc 3x - 1 = 20, 3x = 21, x = 7.', '3x - 6 + 5 = 20, so 3x - 1 = 20, 3x = 21, x = 7.', '3x - 6 + 5 = 20, dus 3x - 1 = 20, 3x = 21, x = 7.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('N4_s_81', 'N4', 3, 'Résous : (2x + 1)/3 = 5', 'Solve: (2x + 1)/3 = 5', 'Los op: (2x + 1)/3 = 5', '7', 0, '2x + 1 = 15, donc 2x = 14, x = 7.', '2x + 1 = 15, so 2x = 14, x = 7.', '2x + 1 = 15, dus 2x = 14, x = 7.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('N4_s_82', 'N4', 3, 'Résous : (3x - 5)/2 = 7', 'Solve: (3x - 5)/2 = 7', 'Los op: (3x - 5)/2 = 7', '6.333333333333333', 0.01, '3x - 5 = 14, donc 3x = 19, x ≈ 6,33.', '3x - 5 = 14, so 3x = 19, x ≈ 6.33.', '3x - 5 = 14, dus 3x = 19, x ≈ 6,33.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('N4_s_83', 'N4', 3, 'Résous : 2x/5 - 1 = 5', 'Solve: 2x/5 - 1 = 5', 'Los op: 2x/5 - 1 = 5', '15', 0, '2x/5 = 6, donc 2x = 30, x = 15.', '2x/5 = 6, so 2x = 30, x = 15.', '2x/5 = 6, dus 2x = 30, x = 15.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('N4_s_84', 'N4', 3, 'Résous : 7x - (5 + 3x) = 0', 'Solve: 7x - (5 + 3x) = 0', 'Los op: 7x - (5 + 3x) = 0', '1.25', 0, '7x - 5 - 3x = 0, donc 4x = 5, x = 1,25.', '7x - 5 - 3x = 0, so 4x = 5, x = 1.25.', '7x - 5 - 3x = 0, dus 4x = 5, x = 1,25.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('N4_s_85', 'N4', 3, 'Résous : 3(x - 4) + 2 = 6', 'Solve: 3(x - 4) + 2 = 6', 'Los op: 3(x - 4) + 2 = 6', '5.333333333333333', 0.01, '3x - 10 = 6, donc 3x = 16, x = 16/3 ≈ 5,33.', '3x - 10 = 6, so 3x = 16, x = 16/3 ≈ 5.33.', '3x - 10 = 6, dus 3x = 16, x = 16/3 ≈ 5,33.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('N4_s_86', 'N4', 3, 'Martin économise pendant 3 mois. Le 2ᵉ mois, il économise 20 € de plus que le 1ᵉʳ. Le 3ᵉ mois, le double du 1ᵉʳ. Total : 170 €. Combien a-t-il économisé le 1ᵉʳ mois ?', 'Martin saves for 3 months. Month 2 he saves 20€ more than month 1. Month 3, double of month 1. Total: 170€. How much did he save in month 1?', 'Martin spaart 3 maanden. Maand 2 spaart hij 20€ meer dan maand 1. Maand 3, het dubbele van maand 1. Totaal: 170€. Hoeveel spaarde hij maand 1?', '37.5', 0, 'x + (x + 20) + 2x = 170, donc 4x + 20 = 170, 4x = 150, x = 37,50.', 'x + (x + 20) + 2x = 170, so 4x + 20 = 170, 4x = 150, x = 37.50.', 'x + (x + 20) + 2x = 170, dus 4x + 20 = 170, 4x = 150, x = 37,50.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('N5_s_1', 'N5', 1, 'Calcule : 3,5 + 2,7', 'Calculate: 3.5 + 2.7', 'Bereken: 3,5 + 2,7', '6.2', 0.01, 'Additionne les dixièmes, puis les unités.', 'Add the tenths, then the units.', 'Tel de tienden op, dan de eenheden.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('N5_s_2', 'N5', 1, 'Calcule : 10,4 - 3,8', 'Calculate: 10.4 - 3.8', 'Bereken: 10,4 - 3,8', '6.6', 0.01, 'Soustrais les dixièmes, puis les unités.', 'Subtract the tenths, then the units.', 'Trek de tienden af, dan de eenheden.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('N5_s_3', 'N5', 1, 'Calcule : 5,2 + 1,3', 'Calculate: 5.2 + 1.3', 'Bereken: 5,2 + 1,3', '6.5', 0.01, 'Aligne les virgules et additionne.', 'Align the decimals and add.', 'Lijn de komma''s uit en tel op.');
