INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('N5_s_17', 'N5', 1, 'Calcule : 15,8 - 7,3', 'Calculate: 15.8 - 7.3', 'Bereken: 15,8 - 7,3', '8.5', 0.01, '0,8 - 0,3 = 0,5. Puis 15 - 7 = 8.', '0.8 - 0.3 = 0.5. Then 15 - 7 = 8.', '0,8 - 0,3 = 0,5. Dan 15 - 7 = 8.');
