INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('N6_s_3', 'N6', 1, 'Calcule : 5²', 'Calculate: 5²', 'Bereken: 5²', '25', 0, '5² = 5 . 5', '5² = 5 . 5', '5² = 5 . 5');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('N6_s_4', 'N6', 1, 'Calcule : 10³', 'Calculate: 10³', 'Bereken: 10³', '1000', 0, '10³ = 10 . 10 . 10', '10³ = 10 . 10 . 10', '10³ = 10 . 10 . 10');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('N6_s_5', 'N6', 1, 'Calcule : 7²', 'Calculate: 7²', 'Bereken: 7²', '49', 0, '7² = 7 . 7', '7² = 7 . 7', '7² = 7 . 7');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('N6_s_16', 'N6', 1, 'Calcule : 4³', 'Calculate: 4³', 'Bereken: 4³', '64', 0, '4³ = 4 . 4 . 4 = 64', '4³ = 4 . 4 . 4 = 64', '4³ = 4 . 4 . 4 = 64');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('N6_s_17', 'N6', 1, 'Calcule : 6²', 'Calculate: 6²', 'Bereken: 6²', '36', 0, '6² = 6 . 6 = 36', '6² = 6 . 6 = 36', '6² = 6 . 6 = 36');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('N6_s_6', 'N6', 2, 'Calcule : 2³ . 2²', 'Calculate: 2³ . 2²', 'Bereken: 2³ . 2²', '32', 0, '2³ = 8 et 2² = 4. Donc 8 . 4 = 32.', '2³ = 8 and 2² = 4. So 8 . 4 = 32.', '2³ = 8 en 2² = 4. Dus 8 . 4 = 32.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('N6_s_7', 'N6', 2, 'Calcule : 3² . 3', 'Calculate: 3² . 3', 'Bereken: 3² . 3', '27', 0, '3² = 9, puis 9 . 3 = 27.', '3² = 9, then 9 . 3 = 27.', '3² = 9, dan 9 . 3 = 27.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('N6_s_8', 'N6', 2, 'Calcule : 4³ : 4', 'Calculate: 4³ : 4', 'Bereken: 4³ : 4', '16', 0, '4³ = 64, puis 64 : 4 = 16.', '4³ = 64, then 64 : 4 = 16.', '4³ = 64, dan 64 : 4 = 16.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('N6_s_9', 'N6', 2, 'Calcule : 5² + 3²', 'Calculate: 5² + 3²', 'Bereken: 5² + 3²', '34', 0, '5² = 25 et 3² = 9. Donc 25 + 9 = 34.', '5² = 25 and 3² = 9. So 25 + 9 = 34.', '5² = 25 en 3² = 9. Dus 25 + 9 = 34.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('N6_s_10', 'N6', 2, 'Calcule : 2⁵', 'Calculate: 2⁵', 'Bereken: 2⁵', '32', 0, '2⁵ = 2 . 2 . 2 . 2 . 2 = 32', '2⁵ = 2 . 2 . 2 . 2 . 2 = 32', '2⁵ = 2 . 2 . 2 . 2 . 2 = 32');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('N6_s_28', 'N6', 2, 'Calcule : 3² - 2³', 'Calculate: 3² - 2³', 'Bereken: 3² - 2³', '1', 0, '3² = 9 et 2³ = 8. Donc 9 - 8 = 1.', '3² = 9 and 2³ = 8. So 9 - 8 = 1.', '3² = 9 en 2³ = 8. Dus 9 - 8 = 1.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('N6_s_29', 'N6', 2, 'Calcule : 4² + 2³', 'Calculate: 4² + 2³', 'Bereken: 4² + 2³', '24', 0, '4² = 16 et 2³ = 8. Donc 16 + 8 = 24.', '4² = 16 and 2³ = 8. So 16 + 8 = 24.', '4² = 16 en 2³ = 8. Dus 16 + 8 = 24.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('N6_s_11', 'N6', 3, 'Calcule : (-3)³', 'Calculate: (-3)³', 'Bereken: (-3)³', '-27', 0, '(-3)³ = (-3) . (-3) . (-3) = 9 . (-3) = -27', '(-3)³ = (-3) . (-3) . (-3) = 9 . (-3) = -27', '(-3)³ = (-3) . (-3) . (-3) = 9 . (-3) = -27');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('N6_s_12', 'N6', 3, 'Calcule : (-2)⁴', 'Calculate: (-2)⁴', 'Bereken: (-2)⁴', '16', 0, 'Exposant pair : le résultat est positif. (-2)⁴ = 16.', 'Even exponent: result is positive. (-2)⁴ = 16.', 'Even exponent: resultaat is positief. (-2)⁴ = 16.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('N6_s_13', 'N6', 3, 'Calcule : (2³)²', 'Calculate: (2³)²', 'Bereken: (2³)²', '64', 0, '2³ = 8, puis 8² = 64.', '2³ = 8, then 8² = 64.', '2³ = 8, dan 8² = 64.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('N6_s_14', 'N6', 3, 'Calcule : (-5)² - 3³', 'Calculate: (-5)² - 3³', 'Bereken: (-5)² - 3³', '-2', 0, '(-5)² = 25 et 3³ = 27. Donc 25 - 27 = -2.', '(-5)² = 25 and 3³ = 27. So 25 - 27 = -2.', '(-5)² = 25 en 3³ = 27. Dus 25 - 27 = -2.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('N6_s_15', 'N6', 3, 'Calcule : 2⁴ + (-3)²', 'Calculate: 2⁴ + (-3)²', 'Bereken: 2⁴ + (-3)²', '25', 0, '2⁴ = 16 et (-3)² = 9. Donc 16 + 9 = 25.', '2⁴ = 16 and (-3)² = 9. So 16 + 9 = 25.', '2⁴ = 16 en (-3)² = 9. Dus 16 + 9 = 25.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('N6_s_40', 'N6', 3, 'Calcule : (-2)³', 'Calculate: (-2)³', 'Bereken: (-2)³', '-8', 0, '(-2)³ = (-2) . (-2) . (-2) = 4 . (-2) = -8', '(-2)³ = (-2) . (-2) . (-2) = 4 . (-2) = -8', '(-2)³ = (-2) . (-2) . (-2) = 4 . (-2) = -8');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('G1_s_1', 'G1', 1, 'Calcule le périmètre d''un rectangle de 8 cm de longueur et 5 cm de largeur.', 'Calculate the perimeter of a rectangle with length 8 cm and width 5 cm.', 'Bereken de omtrek van een rechthoek met lengte 8 cm en breedte 5 cm.', '26', 0, 'Périmètre = 2 . (longueur + largeur) = 2 . (8 + 5).', 'Perimeter = 2 . (length + width) = 2 . (8 + 5).', 'Omtrek = 2 . (lengte + breedte) = 2 . (8 + 5).');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('G1_s_2', 'G1', 1, 'Un rectangle mesure 12 cm de long et 4 cm de large. Quel est son périmètre ?', 'A rectangle is 12 cm long and 4 cm wide. What is its perimeter?', 'Een rechthoek is 12 cm lang en 4 cm breed. Wat is de omtrek?', '32', 0, 'P = 2 . (12 + 4).', 'P = 2 . (12 + 4).', 'P = 2 . (12 + 4).');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('G1_s_3', 'G1', 1, 'Calcule le périmètre d''un rectangle de 15 cm sur 7 cm.', 'Calculate the perimeter of a 15 cm by 7 cm rectangle.', 'Bereken de omtrek van een rechthoek van 15 cm op 7 cm.', '44', 0, 'P = 2 . (15 + 7) = 2 . 22.', 'P = 2 . (15 + 7) = 2 . 22.', 'P = 2 . (15 + 7) = 2 . 22.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('G1_s_4', 'G1', 1, 'Un rectangle a une longueur de 10 cm et une largeur de 3 cm. Calcule son périmètre.', 'A rectangle has a length of 10 cm and a width of 3 cm. Calculate its perimeter.', 'Een rechthoek heeft een lengte van 10 cm en een breedte van 3 cm. Bereken de omtrek.', '26', 0, 'P = 2 . (10 + 3).', 'P = 2 . (10 + 3).', 'P = 2 . (10 + 3).');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('G1_s_5', 'G1', 1, 'Quel est le périmètre d''un rectangle de 6 cm sur 9 cm ?', 'What is the perimeter of a 6 cm by 9 cm rectangle?', 'Wat is de omtrek van een rechthoek van 6 cm op 9 cm?', '30', 0, 'P = 2 . (6 + 9) = 2 . 15.', 'P = 2 . (6 + 9) = 2 . 15.', 'P = 2 . (6 + 9) = 2 . 15.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('G1_s_6', 'G1', 1, 'Calcule le périmètre d''un carré de côté 7 cm.', 'Calculate the perimeter of a square with side 7 cm.', 'Bereken de omtrek van een vierkant met zijde 7 cm.', '28', 0, 'Périmètre d''un carré = 4 . côté = 4 . 7.', 'Perimeter of a square = 4 . side = 4 . 7.', 'Omtrek van een vierkant = 4 . zijde = 4 . 7.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('G1_s_7', 'G1', 1, 'Un carré a un côté de 11 cm. Quel est son périmètre ?', 'A square has a side of 11 cm. What is its perimeter?', 'Een vierkant heeft een zijde van 11 cm. Wat is de omtrek?', '44', 0, 'P = 4 . 11.', 'P = 4 . 11.', 'P = 4 . 11.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('G1_s_18', 'G1', 2, 'Le périmètre d''un rectangle est 30 cm et sa longueur est 10 cm. Quelle est sa largeur ?', 'The perimeter of a rectangle is 30 cm and its length is 10 cm. What is its width?', 'De omtrek van een rechthoek is 30 cm en de lengte is 10 cm. Wat is de breedte?', '5', 0, 'P = 2 . (L + l). Donc 30 = 2 . (10 + l). Résous pour trouver l.', 'P = 2 . (L + w). So 30 = 2 . (10 + w). Solve for w.', 'P = 2 . (L + b). Dus 30 = 2 . (10 + b). Los op naar b.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('G1_s_19', 'G1', 2, 'Un rectangle a un périmètre de 42 cm. Sa largeur est de 8 cm. Quelle est sa longueur ?', 'A rectangle has a perimeter of 42 cm. Its width is 8 cm. What is its length?', 'Een rechthoek heeft een omtrek van 42 cm. De breedte is 8 cm. Wat is de lengte?', '13', 0, '42 = 2 . (L + 8). Divise par 2, puis soustrais 8.', '42 = 2 . (L + 8). Divide by 2, then subtract 8.', '42 = 2 . (L + 8). Deel door 2, trek dan 8 af.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('G1_s_20', 'G1', 2, 'Le périmètre d''un rectangle est 56 cm. Sa longueur est 18 cm. Quelle est sa largeur ?', 'The perimeter of a rectangle is 56 cm. Its length is 18 cm. What is its width?', 'De omtrek van een rechthoek is 56 cm. De lengte is 18 cm. Wat is de breedte?', '10', 0, '56 = 2 . (18 + l). Calcule la demi-somme puis soustrais 18.', '56 = 2 . (18 + w). Find half the perimeter, then subtract 18.', '56 = 2 . (18 + b). Bereken de helft, trek dan 18 af.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('G1_s_21', 'G1', 2, 'Un carré a un périmètre de 48 cm. Quelle est la longueur de son côté ?', 'A square has a perimeter of 48 cm. What is the length of its side?', 'Een vierkant heeft een omtrek van 48 cm. Wat is de lengte van de zijde?', '12', 0, 'Côté = périmètre : 4 = 48 : 4.', 'Side = perimeter / 4 = 48 / 4.', 'Zijde = omtrek / 4 = 48 / 4.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('G1_s_22', 'G1', 2, 'Le périmètre d''un carré est 60 cm. Quel est son côté ?', 'The perimeter of a square is 60 cm. What is its side?', 'De omtrek van een vierkant is 60 cm. Wat is de zijde?', '15', 0, 'Côté = 60 : 4.', 'Side = 60 / 4.', 'Zijde = 60 / 4.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('G1_s_23', 'G1', 2, 'Un carré a un périmètre de 36 cm. Quel est son côté ?', 'A square has a perimeter of 36 cm. What is its side?', 'Een vierkant heeft een omtrek van 36 cm. Wat is de zijde?', '9', 0, 'Côté = 36 : 4.', 'Side = 36 / 4.', 'Zijde = 36 / 4.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('G1_s_24', 'G1', 2, 'Un triangle isocèle a deux côtés de 8 cm et une base de 6 cm. Quel est son périmètre ?', 'An isosceles triangle has two sides of 8 cm and a base of 6 cm. What is its perimeter?', 'Een gelijkbenige driehoek heeft twee zijden van 8 cm en een basis van 6 cm. Wat is de omtrek?', '22', 0, 'P = 8 + 8 + 6.', 'P = 8 + 8 + 6.', 'P = 8 + 8 + 6.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('G1_s_35', 'G1', 3, 'Calcule le périmètre d''un hexagone régulier de côté 5 cm.', 'Calculate the perimeter of a regular hexagon with side 5 cm.', 'Bereken de omtrek van een regelmatige zeshoek met zijde 5 cm.', '30', 0, 'Un hexagone régulier a 6 côtés égaux. P = 6 . 5.', 'A regular hexagon has 6 equal sides. P = 6 . 5.', 'Een regelmatige zeshoek heeft 6 gelijke zijden. P = 6 . 5.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('G1_s_36', 'G1', 3, 'On clôture un jardin rectangulaire de 25 m sur 15 m, mais on laisse une ouverture de 3 m pour le portail. Quelle longueur de clôture faut-il ?', 'A rectangular garden 25 m by 15 m is fenced, but a 3 m opening is left for a gate. How much fencing is needed?', 'Een rechthoekige tuin van 25 m op 15 m wordt omheind, maar er wordt een opening van 3 m gelaten voor een poort. Hoeveel omheining is er nodig?', '77', 0, 'Calcule d''abord le périmètre complet (2 . (25+15) = 80 m), puis retire l''ouverture de 3 m.', 'First calculate the full perimeter (2 . (25+15) = 80 m), then subtract the 3 m opening.', 'Bereken eerst de volledige omtrek (2 . (25+15) = 80 m), trek dan de opening van 3 m af.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('G1_s_37', 'G1', 3, 'Un terrain rectangulaire de 30 m sur 20 m est bordé par un mur sur un grand côté. On clôture les trois autres côtés. Quelle longueur de clôture faut-il ?', 'A rectangular field 30 m by 20 m has a wall along one long side. The other three sides are fenced. How much fencing is needed?', 'Een rechthoekig terrein van 30 m op 20 m heeft een muur langs een lange zijde. De drie andere zijden worden omheind. Hoeveel omheining is er nodig?', '70', 0, '3 côtés = 20 + 30 + 20 (le mur remplace un grand côté de 30 m).', '3 sides = 20 + 30 + 20 (the wall replaces one 30 m side).', '3 zijden = 20 + 30 + 20 (de muur vervangt een lange zijde van 30 m).');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('G1_s_38', 'G1', 3, 'Calcule le périmètre d''un demi-cercle de diamètre 10 cm. (Utilise pi = 3.14)', 'Calculate the perimeter of a semicircle with diameter 10 cm. (Use pi = 3.14)', 'Bereken de omtrek van een halve cirkel met diameter 10 cm. (Gebruik pi = 3,14)', '25.7', 0.1, 'Périmètre = demi-circonférence + diamètre = (pi . 10 / 2) + 10 = 15,7 + 10.', 'Perimeter = half circumference + diameter = (pi . 10 / 2) + 10 = 15.7 + 10.', 'Omtrek = halve omtrek cirkel + diameter = (pi . 10 / 2) + 10 = 15,7 + 10.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('G1_s_39', 'G1', 3, 'Une pièce en L a la forme d''un grand rectangle de 10 m sur 8 m, avec un coin découpé de 3 m sur 4 m. Calcule le périmètre de cette pièce.', 'An L-shaped room is formed by a 10 m by 8 m rectangle with a 3 m by 4 m corner cut out. Calculate the perimeter of this room.', 'Een L-vormige kamer is gevormd door een rechthoek van 10 m op 8 m met een uitgesneden hoek van 3 m op 4 m. Bereken de omtrek van deze kamer.', '36', 0, 'Parcours le contour : 10 + 8 + 7 + 4 + 3 + 4 = 36 m. La découpe ne change pas le périmètre !', 'Trace the outline: 10 + 8 + 7 + 4 + 3 + 4 = 36 m. The cut-out does not change the perimeter!', 'Volg de omtrek: 10 + 8 + 7 + 4 + 3 + 4 = 36 m. De uitsnijding verandert de omtrek niet!');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('G1_s_40', 'G1', 3, 'Calcule la circonférence d''un cercle de rayon 7 cm. (Utilise pi = 3.14)', 'Calculate the circumference of a circle with radius 7 cm. (Use pi = 3.14)', 'Bereken de omtrek van een cirkel met straal 7 cm. (Gebruik pi = 3,14)', '43.96', 0.1, 'C = 2 . pi . rayon = 2 . 3,14 . 7.', 'C = 2 . pi . radius = 2 . 3.14 . 7.', 'C = 2 . pi . straal = 2 . 3,14 . 7.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('G2_new_1', 'G2', 1, 'Ses diagonales sont ses seuls axes de symétrie → ______', 'Ses diagonales sont ses seuls axes of symétrie → ______', 'Ses diagonales sont ses seuls axes van symétrie → ______', 'Losange', 0.01, 'Compte les diagonales avec la formule n(n-3)/2 pour un polygone à n côtés.', 'Count diagonals with formula n(n-3)/2 for an n-sided polygon.', 'Tel diagonalen met formule n(n-3)/2 voor een n-hoek.');
