INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('G4_new_11', 'G4', 2, 'Un triangle isocèle en B a un angle A de 52°. CALCULE l’angle C.', 'Un triangle isocèle en B a un angle A of 52°. Calculate l’angle C.', 'Un triangle isocèle en B a un angle A van 52°. Bereken l’angle C.', '52', 0.01, 'Utilise les propriétés des triangles : somme des angles = 180°, types de triangles.', 'Use triangle properties: sum of angles = 180°, types of triangles.', 'Gebruik driehoekseigenschappen: som van hoeken = 180°, soorten driehoeken.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('G4_new_12', 'G4', 2, 'Un triangle a deux angles de 70° et 50°. CALCULE le troisième angle.', 'Un triangle a ofux angles of 70° et 50°. Calculate le troisième angle.', 'Un triangle a vanux angles van 70° et 50°. Bereken le troisième angle.', '60', 0.01, 'Utilise les propriétés des triangles : somme des angles = 180°, types de triangles.', 'Use triangle properties: sum of angles = 180°, types of triangles.', 'Gebruik driehoekseigenschappen: som van hoeken = 180°, soorten driehoeken.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('G4_add_24', 'G4', 2, 'Dans un triangle isocèle, l''angle au sommet vaut 36°. Calcule un angle de base.', 'In an isosceles triangle, the apex angle is 36°. Calculate a base angle.', 'In een gelijkbenige driehoek is de tophoek 36°. Bereken een basishoek.', '72', 0, 'Dans un triangle isocèle, les deux angles de base sont égaux.', 'In an isosceles triangle, the two base angles are equal.', 'In een gelijkbenige driehoek zijn de twee basishoeken gelijk.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('G4_add_25', 'G4', 2, 'Dans un triangle, les trois angles sont dans le rapport 2:3:4. Calcule le plus grand angle.', 'In a triangle, the three angles are in the ratio 2:3:4. Calculate the largest angle.', 'In een driehoek zijn de drie hoeken in de verhouding 2:3:4. Bereken de grootste hoek.', '80', 0, 'Si les angles sont 2x, 3x et 4x, alors 2x + 3x + 4x = 180.', 'If the angles are 2x, 3x and 4x, then 2x + 3x + 4x = 180.', 'Als de hoeken 2x, 3x en 4x zijn, dan is 2x + 3x + 4x = 180.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('G4_add_26', 'G4', 2, 'Dans un triangle, les trois angles sont dans le rapport 1:2:3. Calcule le plus petit angle.', 'In a triangle, the three angles are in the ratio 1:2:3. Calculate the smallest angle.', 'In een driehoek zijn de drie hoeken in de verhouding 1:2:3. Bereken de kleinste hoek.', '30', 0, 'Si les angles sont x, 2x et 3x, alors x + 2x + 3x = 180.', 'If the angles are x, 2x and 3x, then x + 2x + 3x = 180.', 'Als de hoeken x, 2x en 3x zijn, dan is x + 2x + 3x = 180.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('G4_add_27', 'G4', 2, 'Un triangle a deux angles égaux de 52°. Calcule le troisième angle.', 'A triangle has two equal angles of 52°. Calculate the third angle.', 'Een driehoek heeft twee gelijke hoeken van 52°. Bereken de derde hoek.', '76', 0, 'La somme des angles d''un triangle est 180°.', 'The sum of angles in a triangle is 180°.', 'De som van de hoeken in een driehoek is 180°.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('G4_add_28', 'G4', 2, 'Dans un triangle, un angle vaut le double d''un autre. Le troisième angle vaut 80°. Calcule le plus grand des deux premiers angles.', 'In a triangle, one angle is twice another. The third angle is 80°. Calculate the larger of the first two angles.', 'In een driehoek is één hoek twee keer een andere. De derde hoek is 80°. Bereken de grootste van de eerste twee hoeken.', '66.67', 0.1, 'Si un angle est x, l''autre est 2x. Alors x + 2x + 80 = 180.', 'If one angle is x, the other is 2x. Then x + 2x + 80 = 180.', 'Als één hoek x is, is de andere 2x. Dan is x + 2x + 80 = 180.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('G4_add_47', 'G4', 3, 'Dans un triangle, un angle extérieur vaut 125°. Un angle intérieur non adjacent vaut 68°. Calcule l''autre angle intérieur non adjacent.', 'In a triangle, an exterior angle is 125°. One non-adjacent interior angle is 68°. Calculate the other non-adjacent interior angle.', 'In een driehoek is een buitenhoek 125°. Eén niet-aangrenzende binnenhoek is 68°. Bereken de andere niet-aangrenzende binnenhoek.', '57', 0, 'Un angle extérieur égale la somme des deux angles intérieurs non adjacents.', 'An exterior angle equals the sum of the two non-adjacent interior angles.', 'Een buitenhoek is gelijk aan de som van de twee niet-aangrenzende binnenhoeken.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('G4_add_48', 'G4', 3, 'Dans un triangle, les angles sont (x), (2x-10) et (3x+10). Calcule le plus grand angle.', 'In a triangle, the angles are (x), (2x-10) and (3x+10). Calculate the largest angle.', 'In een driehoek zijn de hoeken (x), (2x-10) en (3x+10). Bereken de grootste hoek.', '100', 0, 'Résous l''équation x + (2x-10) + (3x+10) = 180.', 'Solve the equation x + (2x-10) + (3x+10) = 180.', 'Los de vergelijking x + (2x-10) + (3x+10) = 180 op.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('G4_add_49', 'G4', 3, 'Triangle ABC: l''angle A vaut le double de B, et C vaut 20° de plus que B. Calcule l''angle B.', 'Triangle ABC: angle A is twice B, and C is 20° more than B. Calculate angle B.', 'Driehoek ABC: hoek A is twee keer B, en C is 20° meer dan B. Bereken hoek B.', '40', 0, 'Si B = x, alors A = 2x et C = x + 20. Résous 2x + x + (x + 20) = 180.', 'If B = x, then A = 2x and C = x + 20. Solve 2x + x + (x + 20) = 180.', 'Als B = x, dan is A = 2x en C = x + 20. Los op 2x + x + (x + 20) = 180.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('G4_add_50', 'G4', 3, 'Dans un triangle isocèle, chaque angle de base vaut 4 fois l''angle au sommet. Calcule l''angle au sommet.', 'In an isosceles triangle, each base angle is 4 times the apex angle. Calculate the apex angle.', 'In een gelijkbenige driehoek is elke basishoek 4 keer de tophoek. Bereken de tophoek.', '20', 0, 'Si l''angle au sommet est x, chaque angle de base est 4x. Résous x + 4x + 4x = 180.', 'If the apex angle is x, each base angle is 4x. Solve x + 4x + 4x = 180.', 'Als de tophoek x is, is elke basishoek 4x. Los op x + 4x + 4x = 180.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('G4_add_51', 'G4', 3, 'Dans un triangle, un angle extérieur vaut 152°. Les deux angles intérieurs non adjacents sont dans le rapport 2:3. Calcule le plus grand de ces deux angles.', 'In a triangle, an exterior angle is 152°. The two non-adjacent interior angles are in the ratio 2:3. Calculate the larger of these two angles.', 'In een driehoek is een buitenhoek 152°. De twee niet-aangrenzende binnenhoeken zijn in de verhouding 2:3. Bereken de grootste van deze twee hoeken.', '91.2', 0.2, 'Si les angles sont 2x et 3x, alors 2x + 3x = 152.', 'If the angles are 2x and 3x, then 2x + 3x = 152.', 'Als de hoeken 2x en 3x zijn, dan is 2x + 3x = 152.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('G4_add_52', 'G4', 3, 'Dans un triangle ABC, l''angle A vaut (3x), B vaut (2x+15) et C vaut (x+15). Calcule l''angle C.', 'In triangle ABC, angle A is (3x), B is (2x+15) and C is (x+15). Calculate angle C.', 'In driehoek ABC is hoek A (3x), B is (2x+15) en C is (x+15). Bereken hoek C.', '40', 0, 'Résous 3x + (2x+15) + (x+15) = 180, puis calcule x+15.', 'Solve 3x + (2x+15) + (x+15) = 180, then calculate x+15.', 'Los op 3x + (2x+15) + (x+15) = 180, bereken dan x+15.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('G5_new_1', 'G5', 1, 'Les longueurs de deux côtés sont 9 cm et 4 cm. Détermine la plus petite valeur entière possible du troisième côté. Justifie.', 'Les longueurs of ofux côtés sont 9 cm et 4 cm. oftermine la plus petite valeur entière possible du troisième côté. Justifie.', 'Les longueurs van vanux côtés sont 9 cm et 4 cm. Bepaal la plus petite valeur entière possible du troisième côté. Justifie.', '|9 − 4| < x < 13 → 5 < x < 13 → plus petite valeur entière : 6.', 0.01, 'Inégalité triangulaire : la somme de 2 côtés doit être > au 3e côté.', 'Triangle inequality: sum of 2 sides must be > the 3rd side.', 'Driehoeksongelijkheid: som van 2 zijden moet > de 3e zijde zijn.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('G5_new_2', 'G5', 1, 'Les longueurs de deux côtés sont 12 cm et 5 cm. Détermine la plus petite valeur entière possible du troisième côté. Justifie.', 'Les longueurs of ofux côtés sont 12 cm et 5 cm. oftermine la plus petite valeur entière possible du troisième côté. Justifie.', 'Les longueurs van vanux côtés sont 12 cm et 5 cm. Bepaal la plus petite valeur entière possible du troisième côté. Justifie.', '|12 − 5| < x < 17 → 7 < x < 17 → plus petite valeur entière : 8.', 0.01, 'Inégalité triangulaire : la somme de 2 côtés doit être > au 3e côté.', 'Triangle inequality: sum of 2 sides must be > the 3rd side.', 'Driehoeksongelijkheid: som van 2 zijden moet > de 3e zijde zijn.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('G5_new_3', 'G5', 1, 'Les longueurs de deux côtés sont 15 cm et 7 cm. Détermine la plus grande valeur entière possible du troisième côté. Justifie.', 'Les longueurs of ofux côtés sont 15 cm et 7 cm. oftermine la plus granof valeur entière possible du troisième côté. Justifie.', 'Les longueurs van vanux côtés sont 15 cm et 7 cm. Bepaal la plus granvan valeur entière possible du troisième côté. Justifie.', '|15 − 7| < x < 22 → 8 < x < 22 → plus grande valeur entière : 21.', 0.01, 'Inégalité triangulaire : la somme de 2 côtés doit être > au 3e côté.', 'Triangle inequality: sum of 2 sides must be > the 3rd side.', 'Driehoeksongelijkheid: som van 2 zijden moet > de 3e zijde zijn.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('G5_new_4', 'G5', 1, 'Peut-on construire un triangle de côtés 5 cm, 7 cm et 12 cm ? Justifie.', 'Peut-on construire un triangle of côtés 5 cm, 7 cm et 12 cm ? Justifie.', 'Peut-on construire un triangle van côtés 5 cm, 7 cm et 12 cm ? Justifie.', 'Impossible car 5 + 7 = 12 (égalité).', 0.01, 'Inégalité triangulaire : la somme de 2 côtés doit être > au 3e côté.', 'Triangle inequality: sum of 2 sides must be > the 3rd side.', 'Driehoeksongelijkheid: som van 2 zijden moet > de 3e zijde zijn.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('G5_new_5', 'G5', 1, 'Peut-on construire un triangle de côtés 6 cm, 9 cm et 4 cm ? Justifie.', 'Peut-on construire un triangle of côtés 6 cm, 9 cm et 4 cm ? Justifie.', 'Peut-on construire un triangle van côtés 6 cm, 9 cm et 4 cm ? Justifie.', 'Possible car 3 < 4 < 15.', 0.01, 'Inégalité triangulaire : la somme de 2 côtés doit être > au 3e côté.', 'Triangle inequality: sum of 2 sides must be > the 3rd side.', 'Driehoeksongelijkheid: som van 2 zijden moet > de 3e zijde zijn.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('G5_new_6', 'G5', 1, 'Les côtés mesurent 6 cm, 7 cm et 8 cm. Ce triangle est-il scalène, isocèle ou impossible ? Justifie.', 'Les côtés mesurent 6 cm, 7 cm et 8 cm. Ce triangle est-il scalène, isocèle ou impossible ? Justifie.', 'Les côtés mesurent 6 cm, 7 cm et 8 cm. Ce triangle est-il scalène, isocèle ou impossible ? Justifie.', 'Possible et scalène (trois côtés différents).', 0.01, 'Inégalité triangulaire : la somme de 2 côtés doit être > au 3e côté.', 'Triangle inequality: sum of 2 sides must be > the 3rd side.', 'Driehoeksongelijkheid: som van 2 zijden moet > de 3e zijde zijn.');
