INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('G5_gen_11', 'G5', 2, 'Peut-on construire un triangle de côtés 3 cm, 4 cm et 7 cm ? (1=oui, 0=non)', 'Can we build a triangle with sides 3 cm, 4 cm and 7 cm? (1=yes, 0=no)', 'Kunnen we een driehoek bouwen met zijden 3 cm, 4 cm en 7 cm? (1=ja, 0=nee)', '0', 0, 'Vérifie que la somme de deux côtés est strictement supérieure au troisième.', 'Check that the sum of two sides is strictly greater than the third.', 'Controleer dat de som van twee zijden strikt groter is dan de derde.');
