INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('G5_gen_26', 'G5', 3, 'Deux côtés mesurent 5 cm et 8 cm. Quelle est la plus petite valeur entière possible du 3e côté ?', 'Two sides measure 5 cm and 8 cm. What is the smallest integer value possible for the 3rd side?', 'Twee zijden meten 5 cm en 8 cm. Wat is de kleinste gehele waarde mogelijk voor de 3e zijde?', '4', 0, 'Utilise |a - b| < c < a + b pour trouver l''intervalle.', 'Use |a - b| < c < a + b to find the interval.', 'Gebruik |a - b| < c < a + b om het interval te vinden.');
