INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('P1_new_18', 'P1', 3, '8 stylos coûtent 6€. CALCULE le prix pour 4 stylos.', '8 stylos coûtent 6€. Calculate le prix for 4 stylos.', '8 stylos coûtent 6€. Bereken le prix voor 4 stylos.', '3', 0.01, 'Utilise la proportionnalité: si y = k × x, trouve k puis applique-le.', 'Use proportionality: if y = k × x, find k then apply it.', 'Gebruik evenredigheid: als y = k × x, vind k en pas het toe.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('P1_new_19', 'P1', 3, '2€ + 0,20€/min. CALCULE pour 10 min (réponds 0 si NON proportionnel).', '2€ + 0,20€/min. Calculate for 10 min (réponds 0 si NON proportionnel).', '2€ + 0,20€/min. Bereken voor 10 min (réponds 0 si NON proportionnel).', '0', 0.01, 'Utilise la proportionnalité: si y = k × x, trouve k puis applique-le.', 'Use proportionality: if y = k × x, find k then apply it.', 'Gebruik evenredigheid: als y = k × x, vind k en pas het toe.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('P1_new_20', 'P1', 3, '6 m coûtent 9€. CALCULE le prix pour 2 m.', '6 m coûtent 9€. Calculate le prix for 2 m.', '6 m coûtent 9€. Bereken le prix voor 2 m.', '3', 0.01, 'Utilise la proportionnalité: si y = k × x, trouve k puis applique-le.', 'Use proportionality: if y = k × x, find k then apply it.', 'Gebruik evenredigheid: als y = k × x, vind k en pas het toe.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('P1_add_41', 'P1', 3, 'Une recette pour 4 personnes nécessite 300g de farine. Combien faut-il de farine pour 7 personnes ?', 'A recipe for 4 people requires 300g of flour. How much flour is needed for 7 people?', 'Een recept voor 4 personen vereist 300g meel. Hoeveel meel is nodig voor 7 personen?', '525', 0, 'Utilise la règle de trois : (4 → 300) donc (7 → ?)', 'Use the rule of three: (4 → 300) so (7 → ?)', 'Gebruik de regel van drie: (4 → 300) dus (7 → ?)');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('D1_new_1', 'D1', 1, 'Valeurs : 8, 6, 7, 8, 5. CALCULE la moyenne.', 'Valeurs : 8, 6, 7, 8, 5. Calculate la moyenne.', 'Valeurs : 8, 6, 7, 8, 5. Bereken la moyenne.', '6,8', 0.01, 'Utilise les formules de statistiques et probabilités.', 'Use statistics and probability formulas.', 'Gebruik statistieken en kansberekeningsformules.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('D1_new_2', 'D1', 1, 'Valeurs : 12, 17, 15, x, 10. La moyenne est 13. DÉTERMINE x.', 'Valeurs : 12, 17, 15, x, 10. La moyenne est 13. oftermine x.', 'Valeurs : 12, 17, 15, x, 10. La moyenne est 13. Bepaal x.', '11', 0.01, 'Utilise les formules de statistiques et probabilités.', 'Use statistics and probability formulas.', 'Gebruik statistieken en kansberekeningsformules.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('D1_new_3', 'D1', 1, '4 élèves ont une moyenne de 70. Un score 79 doit être corrigé en 75. CALCULE la nouvelle moyenne.', '4 élèves ont une moyenne of 70. Un score 79 doit être corrigé en 75. Calculate la nouvelle moyenne.', '4 élèves ont une moyenne van 70. Un score 79 doit être corrigé en 75. Bereken la nouvelle moyenne.', '69', 0.01, 'Utilise les formules de statistiques et probabilités.', 'Use statistics and probability formulas.', 'Gebruik statistieken en kansberekeningsformules.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('D1_new_4', 'D1', 1, 'Série : 1 apparaît 4 fois, 2 apparaît 5 fois, 3 apparaît 7 fois, 4 apparaît 6 fois, 5 apparaît 7 fois, 6 apparaît 11 fois. DÉTERMINE le mode.', 'Série : 1 apparaît 4 fois, 2 apparaît 5 fois, 3 apparaît 7 fois, 4 apparaît 6 fois, 5 apparaît 7 fois, 6 apparaît 11 fois. oftermine le moof.', 'Série : 1 apparaît 4 fois, 2 apparaît 5 fois, 3 apparaît 7 fois, 4 apparaît 6 fois, 5 apparaît 7 fois, 6 apparaît 11 fois. Bepaal le movan.', '6', 0.01, 'Utilise les formules de statistiques et probabilités.', 'Use statistics and probability formulas.', 'Gebruik statistieken en kansberekeningsformules.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('D1_new_5', 'D1', 1, 'Total de 50 lancers. Le chiffre 2 est sorti 14 fois. CALCULE la fréquence relative du chiffre 2 (réponse décimale).', 'Total of 50 lancers. Le chiffre 2 est sorti 14 fois. Calculate la fréquence relative du chiffre 2 (réponse décimale).', 'Total van 50 lancers. Le chiffre 2 est sorti 14 fois. Bereken la fréquence relative du chiffre 2 (réponse décimale).', '0,28', 0.01, 'Utilise les formules de statistiques et probabilités.', 'Use statistics and probability formulas.', 'Gebruik statistieken en kansberekeningsformules.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('D1_new_6', 'D1', 1, 'Une boîte contient 50 boules numérotées de 1 à 50. CALCULE la fréquence d’obtenir un numéro qui se termine par 9.', 'Une boîte contient 50 boules numérotées of 1 à 50. Calculate la fréquence d’obtenir un numéro qui se termine par 9.', 'Une boîte contient 50 boules numérotées van 1 à 50. Bereken la fréquence d’obtenir un numéro qui se termine par 9.', '0,1', 0.01, 'Utilise les formules de statistiques et probabilités.', 'Use statistics and probability formulas.', 'Gebruik statistieken en kansberekeningsformules.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('D1_new_7', 'D1', 1, 'Un sachet contient 12 bonbons à l’orange, 6 à la menthe, 4 au citron et 2 à la fraise. CALCULE la probabilité d’obtenir un bonbon au citron (réponse décimale).', 'Un sachet contient 12 bonbons à l’orange, 6 à la menthe, 4 au citron et 2 à la fraise. Calculate la probabilité d’obtenir un bonbon au citron (réponse décimale).', 'Un sachet contient 12 bonbons à l’orange, 6 à la menthe, 4 au citron et 2 à la fraise. Bereken la probabilité d’obtenir un bonbon au citron (réponse décimale).', '0,2', 0.01, 'Utilise les formules de statistiques et probabilités.', 'Use statistics and probability formulas.', 'Gebruik statistieken en kansberekeningsformules.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('D1_add_18', 'D1', 2, 'Série: 12, 15, 18, 21, x. La moyenne est 18. Détermine x.', 'Series: 12, 15, 18, 21, x. The mean is 18. Determine x.', 'Reeks: 12, 15, 18, 21, x. Het gemiddelde is 18. Bepaal x.', '24', 0, 'Moyenne = somme / 5, donc 18 = (12 + 15 + 18 + 21 + x) / 5.', 'Mean = sum / 5, so 18 = (12 + 15 + 18 + 21 + x) / 5.', 'Gemiddelde = som / 5, dus 18 = (12 + 15 + 18 + 21 + x) / 5.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('D1_add_19', 'D1', 2, 'Série: 4, 7, 9, 12, 15, 18. Calcule la médiane.', 'Series: 4, 7, 9, 12, 15, 18. Calculate the median.', 'Reeks: 4, 7, 9, 12, 15, 18. Bereken de mediaan.', '10.5', 0, 'Pour un nombre pair d''éléments, la médiane est la moyenne des deux valeurs centrales.', 'For an even number of elements, the median is the average of the two central values.', 'Voor een even aantal elementen is de mediaan het gemiddelde van de twee centrale waarden.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('D1_add_20', 'D1', 2, 'Valeurs: 3, 5, 7, 7, 9, 11, 11, 11. Détermine le mode.', 'Values: 3, 5, 7, 7, 9, 11, 11, 11. Determine the mode.', 'Waarden: 3, 5, 7, 7, 9, 11, 11, 11. Bepaal de modus.', '11', 0, 'Le mode est la valeur qui apparaît le plus souvent.', 'The mode is the value that appears most often.', 'De modus is de waarde die het meest voorkomt.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('D1_add_21', 'D1', 2, 'Deux dés sont lancés. Quelle est la probabilité d''obtenir une somme de 7 ? (réponse décimale, arrondi à 0.01)', 'Two dice are rolled. What is the probability of getting a sum of 7? (decimal answer, round to 0.01)', 'Twee dobbelstenen worden gegooid. Wat is de kans om een som van 7 te krijgen? (decimaal antwoord, rond af op 0.01)', '0.17', 0.01, 'Les combinaisons donnant 7 sont: (1,6), (2,5), (3,4), (4,3), (5,2), (6,1). Total 36 cas possibles.', 'Combinations giving 7 are: (1,6), (2,5), (3,4), (4,3), (5,2), (6,1). Total 36 possible cases.', 'Combinaties die 7 geven zijn: (1,6), (2,5), (3,4), (4,3), (5,2), (6,1). Totaal 36 mogelijke gevallen.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('D1_add_22', 'D1', 2, 'Série: 8, 10, 12, x, 16. La moyenne est 12. Détermine x.', 'Series: 8, 10, 12, x, 16. The mean is 12. Determine x.', 'Reeks: 8, 10, 12, x, 16. Het gemiddelde is 12. Bepaal x.', '14', 0, 'Moyenne = somme / 5, donc 12 = (8 + 10 + 12 + x + 16) / 5.', 'Mean = sum / 5, so 12 = (8 + 10 + 12 + x + 16) / 5.', 'Gemiddelde = som / 5, dus 12 = (8 + 10 + 12 + x + 16) / 5.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('D1_add_23', 'D1', 2, 'Dans un sac, il y a 6 jetons verts, 4 jetons rouges et 5 jetons bleus. Quelle est la probabilité de tirer un jeton rouge ou bleu ? (réponse décimale)', 'In a bag, there are 6 green tokens, 4 red tokens and 5 blue tokens. What is the probability of drawing a red or blue token? (decimal answer)', 'In een zak zitten 6 groene fiches, 4 rode fiches en 5 blauwe fiches. Wat is de kans om een rode of blauwe fiche te trekken? (decimaal antwoord)', '0.6', 0, 'Probabilité = (4 + 5) / (6 + 4 + 5).', 'Probability = (4 + 5) / (6 + 4 + 5).', 'Kans = (4 + 5) / (6 + 4 + 5).');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('D1_add_24', 'D1', 2, 'Série: 2, 5, 8, 11, 14, 17. Calcule la médiane.', 'Series: 2, 5, 8, 11, 14, 17. Calculate the median.', 'Reeks: 2, 5, 8, 11, 14, 17. Bereken de mediaan.', '9.5', 0, 'Pour un nombre pair d''éléments, la médiane est la moyenne des deux valeurs centrales.', 'For an even number of elements, the median is the average of the two central values.', 'Voor een even aantal elementen is de mediaan het gemiddelde van de twee centrale waarden.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('D1_add_35', 'D1', 3, 'Série: 5, 8, 12, 15, 18, 20, 25. Calcule l''étendue (différence entre max et min).', 'Series: 5, 8, 12, 15, 18, 20, 25. Calculate the range (difference between max and min).', 'Reeks: 5, 8, 12, 15, 18, 20, 25. Bereken het bereik (verschil tussen max en min).', '20', 0, 'Étendue = valeur maximale - valeur minimale.', 'Range = maximum value - minimum value.', 'Bereik = maximale waarde - minimale waarde.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('D1_add_36', 'D1', 3, 'Série: 2, 4, 6, 8, 10, 12. Calcule l''écart entre la moyenne et la médiane.', 'Series: 2, 4, 6, 8, 10, 12. Calculate the difference between the mean and the median.', 'Reeks: 2, 4, 6, 8, 10, 12. Bereken het verschil tussen het gemiddelde en de mediaan.', '0', 0, 'Calcule d''abord la moyenne et la médiane, puis leur différence.', 'First calculate the mean and median, then their difference.', 'Bereken eerst het gemiddelde en de mediaan, dan hun verschil.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('D1_add_37', 'D1', 3, 'Dans une urne, il y a 3 boules rouges, 4 boules vertes et 5 boules bleues. On tire 2 boules sans remise. Quelle est la probabilité de tirer 2 boules rouges ? (arrondi à 0.01)', 'In an urn, there are 3 red balls, 4 green balls and 5 blue balls. We draw 2 balls without replacement. What is the probability of drawing 2 red balls? (round to 0.01)', 'In een urn zitten 3 rode ballen, 4 groene ballen en 5 blauwe ballen. We trekken 2 ballen zonder terugleggen. Wat is de kans om 2 rode ballen te trekken? (rond af op 0.01)', '0.05', 0.01, 'Probabilité = (3/12) × (2/11).', 'Probability = (3/12) × (2/11).', 'Kans = (3/12) × (2/11).');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('D1_add_38', 'D1', 3, 'Série: 10, 12, 14, x, 18, 20. La médiane est 15. Détermine x.', 'Series: 10, 12, 14, x, 18, 20. The median is 15. Determine x.', 'Reeks: 10, 12, 14, x, 18, 20. De mediaan is 15. Bepaal x.', '16', 0, 'Pour un nombre pair, la médiane est la moyenne des deux valeurs centrales (14 et x).', 'For an even number, the median is the average of the two central values (14 and x).', 'Voor een even aantal is de mediaan het gemiddelde van de twee centrale waarden (14 en x).');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('D1_add_39', 'D1', 3, 'Un sac contient 10 billes: 4 rouges, 3 bleues et 3 vertes. On tire 2 billes successivement sans remise. Quelle est la probabilité de tirer une rouge puis une bleue ? (arrondi à 0.01)', 'A bag contains 10 marbles: 4 red, 3 blue and 3 green. We draw 2 marbles successively without replacement. What is the probability of drawing a red then a blue? (round to 0.01)', 'Een zak bevat 10 knikkers: 4 rode, 3 blauwe en 3 groene. We trekken 2 knikkers achter elkaar zonder terugleggen. Wat is de kans om eerst een rode en dan een blauwe te trekken? (rond af op 0.01)', '0.13', 0.01, 'Probabilité = (4/10) × (3/9).', 'Probability = (4/10) × (3/9).', 'Kans = (4/10) × (3/9).');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('D1_add_40', 'D1', 3, 'Série: 3, 5, 7, 9, 11, 13, 15, 17. Calcule le 1er quartile (Q1).', 'Series: 3, 5, 7, 9, 11, 13, 15, 17. Calculate the 1st quartile (Q1).', 'Reeks: 3, 5, 7, 9, 11, 13, 15, 17. Bereken het 1e kwartiel (Q1).', '6', 0, 'Q1 est la médiane de la première moitié des données.', 'Q1 is the median of the first half of the data.', 'Q1 is de mediaan van de eerste helft van de gegevens.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('D2_s_1', 'D2', 1, 'Quelle est la moyenne de : 4, 8, 6, 10, 2 ?', 'What is the mean of: 4, 8, 6, 10, 2?', 'Wat is het gemiddelde van: 4, 8, 6, 10, 2?', '6', 0.01, 'Additionne tout, puis divise par 5.', 'Add all, then divide by 5.', 'Tel alles op, deel dan door 5.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('D2_s_2', 'D2', 1, 'Quelle est la moyenne de : 12, 8, 15, 5 ?', 'What is the mean of: 12, 8, 15, 5?', 'Wat is het gemiddelde van: 12, 8, 15, 5?', '10', 0.01, '(12 + 8 + 15 + 5) : 4.', '(12 + 8 + 15 + 5) : 4.', '(12 + 8 + 15 + 5) : 4.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('D2_s_3', 'D2', 1, 'Quelle est la moyenne de : 7, 3, 5, 9, 6 ?', 'What is the mean of: 7, 3, 5, 9, 6?', 'Wat is het gemiddelde van: 7, 3, 5, 9, 6?', '6', 0.01, 'Total = 30. Puis 30 : 5.', 'Total = 30. Then 30 : 5.', 'Totaal = 30. Dan 30 : 5.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('D2_s_4', 'D2', 1, 'Quelle est la moyenne de : 20, 30, 40 ?', 'What is the mean of: 20, 30, 40?', 'Wat is het gemiddelde van: 20, 30, 40?', '30', 0.01, '(20 + 30 + 40) : 3.', '(20 + 30 + 40) : 3.', '(20 + 30 + 40) : 3.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('D2_s_5', 'D2', 1, 'Quelle est la moyenne de : 15, 25, 10, 30 ?', 'What is the mean of: 15, 25, 10, 30?', 'Wat is het gemiddelde van: 15, 25, 10, 30?', '20', 0.01, '(15 + 25 + 10 + 30) : 4.', '(15 + 25 + 10 + 30) : 4.', '(15 + 25 + 10 + 30) : 4.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('D2_s_16', 'D2', 1, 'Quelle est la moyenne de : 3, 9, 6 ?', 'What is the mean of: 3, 9, 6?', 'Wat is het gemiddelde van: 3, 9, 6?', '6', 0.01, '(3 + 9 + 6) : 3 = 18 : 3.', '(3 + 9 + 6) : 3 = 18 : 3.', '(3 + 9 + 6) : 3 = 18 : 3.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('D2_s_17', 'D2', 1, 'Quelle est la moyenne de : 10, 14, 8, 12 ?', 'What is the mean of: 10, 14, 8, 12?', 'Wat is het gemiddelde van: 10, 14, 8, 12?', '11', 0.01, '(10 + 14 + 8 + 12) : 4 = 44 : 4.', '(10 + 14 + 8 + 12) : 4 = 44 : 4.', '(10 + 14 + 8 + 12) : 4 = 44 : 4.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('D2_s_6', 'D2', 2, 'Quel est l''étendue de : 3, 8, 15, 2, 10 ?', 'What is the range of: 3, 8, 15, 2, 10?', 'Wat is het bereik van: 3, 8, 15, 2, 10?', '13', 0, 'Étendue = max - min = 15 - 2.', 'Range = max - min = 15 - 2.', 'Bereik = max - min = 15 - 2.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('D2_s_7', 'D2', 2, 'Quelle est la médiane de : 2, 5, 7, 10, 14 ?', 'What is the median of: 2, 5, 7, 10, 14?', 'Wat is de mediaan van: 2, 5, 7, 10, 14?', '7', 0, 'Les données sont déjà triées. La médiane est la valeur du milieu.', 'Data is already sorted. The median is the middle value.', 'De data is al gesorteerd. De mediaan is de middelste waarde.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('D2_s_8', 'D2', 2, 'Quel est l''étendue de : 12, 4, 18, 7, 9 ?', 'What is the range of: 12, 4, 18, 7, 9?', 'Wat is het bereik van: 12, 4, 18, 7, 9?', '14', 0, '18 - 4 = 14.', '18 - 4 = 14.', '18 - 4 = 14.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('D2_s_9', 'D2', 2, 'Quelle est la médiane de : 3, 6, 9, 12, 15 ?', 'What is the median of: 3, 6, 9, 12, 15?', 'Wat is de mediaan van: 3, 6, 9, 12, 15?', '9', 0, 'Valeur du milieu parmi 5 nombres triés.', 'Middle value of 5 sorted numbers.', 'Middelste waarde van 5 gesorteerde getallen.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('D2_s_10', 'D2', 2, 'La moyenne de 5 nombres est 8. Quel est leur total ?', 'The mean of 5 numbers is 8. What is their total?', 'Het gemiddelde van 5 getallen is 8. Wat is hun totaal?', '40', 0, 'Total = moyenne . nombre de valeurs = 8 . 5.', 'Total = mean . count = 8 . 5.', 'Totaal = gemiddelde . aantal = 8 . 5.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('D2_s_28', 'D2', 2, 'Quel est l''étendue de : 5, 12, 3, 20, 8 ?', 'What is the range of: 5, 12, 3, 20, 8?', 'Wat is het bereik van: 5, 12, 3, 20, 8?', '17', 0, 'Étendue = max - min = 20 - 3.', 'Range = max - min = 20 - 3.', 'Bereik = max - min = 20 - 3.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('D2_s_29', 'D2', 2, 'Quelle est la médiane de : 1, 4, 7, 9, 13 ?', 'What is the median of: 1, 4, 7, 9, 13?', 'Wat is de mediaan van: 1, 4, 7, 9, 13?', '7', 0, 'Les données sont triées. La valeur du milieu est la 3e sur 5.', 'Data is sorted. The middle value is the 3rd of 5.', 'De data is gesorteerd. De middelste waarde is de 3e van 5.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('D2_s_11', 'D2', 3, 'Notes : 12, 8, 15, 9, 6. Combien faut-il au 6e contrôle pour une moyenne de 10 ?', 'Scores: 12, 8, 15, 9, 6. What score is needed on the 6th test for a mean of 10?', 'Punten: 12, 8, 15, 9, 6. Welk punt is nodig op de 6e toets voor een gemiddelde van 10?', '10', 0, '10 . 6 = 60. Total actuel = 50. Il manque 10.', '10 . 6 = 60. Current total = 50. Need 10 more.', '10 . 6 = 60. Huidig totaal = 50. Nog 10 nodig.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('D2_s_12', 'D2', 3, 'La moyenne de 4 nombres est 15. On ajoute 25. Quelle est la nouvelle moyenne ?', 'The mean of 4 numbers is 15. Adding 25 gives what new mean?', 'Het gemiddelde van 4 getallen is 15. Na toevoeging van 25, wat is het nieuwe gemiddelde?', '17', 0.01, 'Total = 60 + 25 = 85. Nouvelle moyenne = 85 : 5.', 'Total = 60 + 25 = 85. New mean = 85 : 5.', 'Totaal = 60 + 25 = 85. Nieuw gemiddelde = 85 : 5.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('D2_s_13', 'D2', 3, 'Données : 3, 5, 5, 7, 8, 8, 8, 10. Quel est le mode ?', 'Data: 3, 5, 5, 7, 8, 8, 8, 10. What is the mode?', 'Data: 3, 5, 5, 7, 8, 8, 8, 10. Wat is de modus?', '8', 0, 'Le mode est la valeur la plus fréquente.', 'The mode is the most frequent value.', 'De modus is de meest voorkomende waarde.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('D2_s_14', 'D2', 3, 'La moyenne de 3 nombres est 12. Les deux premiers sont 10 et 14. Quel est le troisième ?', 'The mean of 3 numbers is 12. The first two are 10 and 14. What is the third?', 'Het gemiddelde van 3 getallen is 12. De eerste twee zijn 10 en 14. Wat is het derde?', '12', 0, 'Total = 36. 36 - 10 - 14 = 12.', 'Total = 36. 36 - 10 - 14 = 12.', 'Totaal = 36. 36 - 10 - 14 = 12.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('D2_s_15', 'D2', 3, 'La moyenne de 6 nombres est 5. On retire le nombre 11. Quelle est la nouvelle moyenne ?', 'The mean of 6 numbers is 5. Removing 11 gives what new mean?', 'Het gemiddelde van 6 getallen is 5. Na verwijdering van 11, wat is het nieuwe gemiddelde?', '3.8', 0.01, 'Total = 30. Nouveau total = 30 - 11 = 19. 19 : 5 = 3,8.', 'Total = 30. New total = 30 - 11 = 19. 19 : 5 = 3.8.', 'Totaal = 30. Nieuw totaal = 30 - 11 = 19. 19 : 5 = 3,8.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('D2_s_40', 'D2', 3, 'Notes : 14, 10, 8, 12, 16. Combien faut-il au 6e contrôle pour une moyenne de 12 ?', 'Scores: 14, 10, 8, 12, 16. What score is needed on the 6th test for a mean of 12?', 'Punten: 14, 10, 8, 12, 16. Welk punt is nodig op de 6e toets voor een gemiddelde van 12?', '12', 0, '12 . 6 = 72. Total actuel = 60. Il manque 12.', '12 . 6 = 72. Current total = 60. Need 12 more.', '12 . 6 = 72. Huidig totaal = 60. Nog 12 nodig.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('M1_s_1', 'M1', 1, 'Combien de mètres dans 3,5 km ?', 'How many meters in 3.5 km?', 'Hoeveel meter in 3,5 km?', '3500', 0, '1 km = 1000 m.', '1 km = 1000 m.', '1 km = 1000 m.');
