INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('M1_s_8', 'M1', 2, 'Convertis 2h30min en minutes.', 'Convert 2h30min to minutes.', 'Reken 2u30min om naar minuten.', '150', 0, '2 . 60 + 30 = 150.', '2 . 60 + 30 = 150.', '2 . 60 + 30 = 150.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('M1_s_9', 'M1', 2, 'Combien de litres dans 4500 mL ?', 'How many liters in 4500 mL?', 'Hoeveel liter in 4500 mL?', '4.5', 0.01, '4500 : 1000 = 4,5.', '4500 : 1000 = 4.5.', '4500 : 1000 = 4,5.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('M1_s_10', 'M1', 2, 'Combien de kg dans 2300 g ?', 'How many kg in 2300 g?', 'Hoeveel kg in 2300 g?', '2.3', 0.01, '2300 : 1000 = 2,3.', '2300 : 1000 = 2.3.', '2300 : 1000 = 2,3.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('M1_s_28', 'M1', 2, 'Combien de cm² dans 3,2 dm² ?', 'How many cm² in 3.2 dm²?', 'Hoeveel cm² in 3,2 dm²?', '320', 0, '1 dm² = 100 cm². 3,2 . 100 = 320.', '1 dm² = 100 cm². 3.2 . 100 = 320.', '1 dm² = 100 cm². 3,2 . 100 = 320.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('M1_s_29', 'M1', 2, 'Combien de mm dans 1,35 m ?', 'How many mm in 1.35 m?', 'Hoeveel mm in 1,35 m?', '1350', 0, '1 m = 1000 mm. 1,35 . 1000 = 1350.', '1 m = 1000 mm. 1.35 . 1000 = 1350.', '1 m = 1000 mm. 1,35 . 1000 = 1350.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('M1_s_11', 'M1', 3, 'Convertis 45 000 cm² en m².', 'Convert 45,000 cm² to m².', 'Reken 45.000 cm² om naar m².', '4.5', 0.01, '1 m² = 10 000 cm². Donc 45 000 : 10 000.', '1 m² = 10,000 cm². So 45,000 : 10,000.', '1 m² = 10.000 cm². Dus 45.000 : 10.000.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('M1_s_12', 'M1', 3, 'Combien de dm³ dans 3,5 litres ?', 'How many dm³ in 3.5 liters?', 'Hoeveel dm³ in 3,5 liter?', '3.5', 0.01, '1 litre = 1 dm³.', '1 liter = 1 dm³.', '1 liter = 1 dm³.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('M1_s_13', 'M1', 3, 'Convertis 2,5 heures en minutes.', 'Convert 2.5 hours to minutes.', 'Reken 2,5 uur om naar minuten.', '150', 0, '2,5 . 60 = 150.', '2.5 . 60 = 150.', '2,5 . 60 = 150.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('M1_s_14', 'M1', 3, 'Combien de m² dans 0,08 hectare ?', 'How many m² in 0.08 hectare?', 'Hoeveel m² in 0,08 hectare?', '800', 0, '1 ha = 10 000 m². Donc 0,08 . 10 000.', '1 ha = 10,000 m². So 0.08 . 10,000.', '1 ha = 10.000 m². Dus 0,08 . 10.000.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('M1_s_15', 'M1', 3, 'Convertis 72 km/h en m/s.', 'Convert 72 km/h to m/s.', 'Reken 72 km/u om naar m/s.', '20', 0.01, ': 3,6 : 72 : 3,6 = 20.', ': 3.6: 72 : 3.6 = 20.', ': 3,6: 72 : 3,6 = 20.');
INSERT INTO questions (id, category, level, text_fr, text_en, text_nl, answer, tolerance, hint_fr, hint_en, hint_nl) VALUES ('M1_s_40', 'M1', 3, 'Convertis 30 000 cm² en m².', 'Convert 30,000 cm² to m².', 'Reken 30.000 cm² om naar m².', '3', 0.01, '1 m² = 10 000 cm². 30 000 : 10 000 = 3.', '1 m² = 10,000 cm². 30,000 : 10,000 = 3.', '1 m² = 10.000 cm². 30.000 : 10.000 = 3.');
